   496→	if e.RHS == nil {
   497→		return posrange.PositionRange{
   498→			Start: e.StartPos,
   499→			End:   e.RHS.PositionRange().End,
   500→		}
   501→	}
   502→	if e.LHS == nil {
   503→		return posrange.PositionRange{
   504→			Start: e.StartPos,
   505→			End:   e.RHS.PositionRange().End,
   506→		}
   507→	}
   508→	return mergeRanges(e.LHS, e.RHS)
   509→}
