func scalarBinop(op parser.ItemType, lhs, rhs float64) float64 {
    switch op {
    case parser.ADD:
        return lhs + rhs
    case parser.SUB:
        return lhs - rhs
    case parser.MUL:
        return lhs * rhs
    case parser.DIV:
        return lhs / rhs
    case parser.POW:
        return math.Pow(lhs, rhs)
    case parser.MOD:
        return math.Mod(lhs, rhs)
    case parser.EQLC:
        return btos(lhs == rhs)
    case parser.NEQ:
        return btos(lhs != rhs)
    case parser.GTR:
        return btos(lhs > rhs)
    case parser.LSS:
        return btos(lhs < rhs)
    case parser.GTE:
        return btos(lhs >= rhs)
    case parser.LTE:
        return btos(lhs <= rhs)
    case parser.ATAN2:
        return math.Atan2(lhs, rhs)
    }
    panic(fmt.Errorf("operator %q not allowed for Scalar operations", op))
}
