func (ev *evaluator) VectorBinop(op parser.ItemType, lhs, rhs Vector, matching *parser.VectorMatching, returnBool bool, lhsh, rhsh []EvalSeriesHelper, enh *EvalNodeHelper, pos posrange.PositionRange) (Vector, error) {
    if matching.Card == parser.CardManyToMany {
        panic("many-to-many only allowed for set operators")
    }
    if (len(lhs) == 0 && len(rhs) == 0) ||
        ((len(lhs) == 0 || len(rhs) == 0) && matching.FillValues.RHS == nil && matching.FillValues.LHS == nil) {
        return nil, nil // Short-circuit: nothing is going to match.
    }

    // The control flow below handles one-to-one or many-to-one matching.
    // For one-to-many, swap sidedness and account for the swap when calculating values.
    if matching.Card == parser.CardOneToMany {
        lhs, rhs = rhs, lhs
        lhsh, rhsh = rhsh, lhsh
    }

    // All samples from the rhs by their join signature ordinal.
    rightSigs := enh.resetRightSigs()
    rightSigsPresent := enh.resetSigsPresent()

    // Add all rhs samples to a map so we can easily find matches later.
    for i, rs := range rhs {
        sigOrd := rhsh[i].sigOrdinal
        // The rhs is guaranteed to be the 'one' side.
        if rightSigsPresent[sigOrd] {
            duplSample := rightSigs[sigOrd]
            oneSide := "right"
            if matching.Card == parser.CardOneToMany {
                oneSide = "left"
            }
            matchedLabels := rs.Metric.MatchLabels(matching.On, matching.MatchingLabels...)
            // Many-to-many matching not allowed.
            ev.errorf("found duplicate series for the match group %s on the %s hand-side of the operation: [%s, %s]"+
                ";many-to-many matching not allowed: matching labels must be unique on one side", matchedLabels.String(), oneSide, rs.Metric.String(), duplSample.Metric.String())
        }
        rightSigs[sigOrd] = rs
        rightSigsPresent[sigOrd] = true
    }

    // ... matching logic and doBinOp callback
    // For all lhs samples, find a respective rhs sample and perform the binary operation.
    for i, ls := range lhs {
        sigOrd := lhsh[i].sigOrdinal
        var rs Sample
        if rightSigsPresent[sigOrd] {
            rs = rightSigs[sigOrd]
        } else {
            fill := matching.FillValues.RHS
            if fill == nil {
                continue
            }
            rs = Sample{
                Metric: ls.Metric.MatchLabels(matching.On, matching.MatchingLabels...),
                F:      *fill,
            }
        }
        doBinOp(ls, rs, sigOrd)
    }

    return enh.Out, lastErr
}
```

**Vector Matching Types:**
- **CardOneToOne:** Each series on LHS matches exactly one on RHS
- **CardManyToOne:** Many series on LHS can match one series on RHS (requires `group_left`)
- **CardOneToMany:** One series on LHS matches many on RHS (requires `group_right`)
- **CardManyToMany:** Not allowed for most operators (only set operators)

