func (ev *evaluator) rangeEval(ctx context.Context, matching *parser.VectorMatching, 
    funcCall func([]Vector, Matrix, [][]EvalSeriesHelper, *EvalNodeHelper) (Vector, annotations.Annotations), 
    exprs ...parser.Expr) (Matrix, annotations.Annotations) {

    numSteps := int((ev.endTimestamp-ev.startTimestamp)/ev.interval) + 1

    // Evaluate all input expressions first
    matrixes := make([]Matrix, len(exprs))
    for i, e := range exprs {
        if e != nil && e.Type() != parser.ValueTypeString {
            val, ws := ev.eval(ctx, e)
            warnings.Merge(ws)
            matrixes[i] = val.(Matrix)
        }
    }

    // For each timestamp in the range, gather vectors and call the function
    for ts := ev.startTimestamp; ts <= ev.endTimestamp; ts += ev.interval {
        if err := contextDone(ctx, "expression evaluation"); err != nil {
            ev.error(err)
        }

        // Gather input vectors for this timestamp
        for i := range exprs {
            vectors[i], bh = ev.gatherVector(ts, matrixes[i], vectors[i], bh, sh)
        }

        // Make the function call at this timestamp
        enh.Ts = ts
        result, ws := funcCall(vectors, nil, bufHelpers, enh)
        enh.Out = result[:0] // Reuse result vector.

        // Accumulate result samples into output series
        for _, sample := range result {
            h := sample.Metric.Hash()
            ss, ok := seriess[h]
            if ok {
                if ss.ts == ts {
                    ev.errorf("vector cannot contain metrics with the same labelset")
                }
                ss.ts = ts
            } else {
                ss = seriesAndTimestamp{Series{Metric: sample.Metric, DropName: sample.DropName}, ts}
            }
            addToSeries(&ss.Series, enh.Ts, sample.F, sample.H, numSteps)
            seriess[h] = ss
        }
    }

    return mat, warnings
}
```

