**File:** `/go/agent-index-go/testdata/fixtures/go/ast.go:336-399`

```go
// Visitor allows visiting a Node and its child nodes.
type Visitor interface {
    Visit(node Node, path []Node) (w Visitor, err error)
}

// Walk traverses an AST in depth-first order
func Walk(v Visitor, node Node, path []Node) error {
    var err error
    if v, err = v.Visit(node, path); v == nil || err != nil {
        return err
    }
    var pathToHere []Node

    for e := range ChildrenIter(node) {
        if pathToHere == nil {
            pathToHere = append(path, node)
        }
        if err := Walk(v, e, pathToHere); err != nil {
            return err
        }
    }

    _, err = v.Visit(nil, nil)
    return err
}

// ChildrenIter returns an iterator over all child nodes
func ChildrenIter(node Node) func(func(Node) bool) {
    return func(yield func(Node) bool) {
        switch n := node.(type) {
        case *EvalStmt:
            yield(n.Expr)
        case *AggregateExpr:
            if n.Expr != nil {
                yield(n.Expr)
            }
            if n.Param != nil {
                yield(n.Param)
            }
        case *BinaryExpr:
            yield(n.LHS)
            yield(n.RHS)
        case *Call:
            for _, e := range n.Args {
                yield(e)
            }
        // ... other node types
        }
    }
}
```

